export const fetchHalls = async (
  setLoading: (loading: boolean) => void,
  toast?: any,
  currentPage = 1,
  hallsPerPage = 3,
  paginate?: boolean
) => {
  const urlWithPagentaion = `http://localhost:8080/halls?page=${currentPage}&perPage=${hallsPerPage}`;
  const url = `http://localhost:8080/halls`;
  try {
    setLoading(true);
    const res = await fetch(`${paginate ? urlWithPagentaion : url}`, {
      method: 'GET',
      headers: {
        'Content-Type': 'application/json',
      },
    });
    if (!res.ok) {
      throw new Error(`Failed to fetch event: ${res.statusText}`);
    }

    const data = await res.json();
    return {
      halls: data.halls || [],
      totalItems: data.totalItems || 0,
      totalPages:
        data.totalPages || Math.ceil((data.totalItems || 0) / hallsPerPage),
    };
  } catch (error: unknown) {
    if (error instanceof Error) {
      toast({
        title: 'Error',
        description: error.message,
        variant: 'destructive',
      });
    } else {
      toast({
        title: 'Error',
        description: 'An unexpected error occurred.',
        variant: 'destructive',
      });
    }
    return { halls: [], totalItems: 0, totalPages: 0 };
  } finally {
    setLoading(false);
  }
};
